import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Box, Paper, Typography, TextField, Button, Alert, InputAdornment, IconButton } from '@mui/material';
import { EnvelopeIcon, LockClosedIcon, EyeIcon, EyeSlashIcon } from '@heroicons/react/24/outline';
import { motion } from 'framer-motion';
import { useAuth } from '../contexts/AuthContext';

// Define admin credentials
const ADMIN_CREDENTIALS = {
  email: 'admin@hunterai.com',
  password: 'HunterAI2025!'
};

const Login: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const { login } = useAuth();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    if (!email || !password) {
      setError('Email and password are required');
      setLoading(false);
      return;
    }

    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setError('Invalid email format');
      setLoading(false);
      return;
    }

    try {
      if (email === ADMIN_CREDENTIALS.email && password === ADMIN_CREDENTIALS.password) {
        localStorage.setItem('token', 'admin-token');
        localStorage.setItem('user', JSON.stringify(ADMIN_CREDENTIALS));
        navigate('/admin/home');
      } else {
        await login(email, password);
        navigate('/applicant/home');
      }
    } catch (err: any) {
      setError(err.message || 'Failed to log in. Please check your credentials.');
    } finally {
      setLoading(false);
    }
  };

  const containerVariants = {
    hidden: { opacity: 0, y: 50 },
    visible: { 
      opacity: 1, 
      y: 0, 
      transition: { 
        duration: 0.5,
        when: "beforeChildren",
        staggerChildren: 0.1
      }
    },
  };

  const childVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0 }
  };

  const buttonVariants = {
    hover: { scale: 1.05, boxShadow: '0px 0px 20px rgba(59, 130, 246, 0.5)' },
    tap: { scale: 0.95 }
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        py: 4,
        bgcolor: '#0a0f24',
        background: 'radial-gradient(circle at center, #1e3a8a 0%, #0a0f24 100%)',
        position: 'relative',
        overflow: 'hidden',
        '&:before': {
          content: '""',
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: 'linear-gradient(45deg, rgba(59,130,246,0.1) 0%, rgba(147,51,234,0.1) 100%)',
          animation: 'pulse 8s infinite'
        }
      }}
    >
      <style>
        {`
          @keyframes pulse {
            0% { opacity: 0.3; }
            50% { opacity: 0.6; }
            100% { opacity: 0.3; }
          }
          @keyframes scan {
            0% { transform: translateY(-100%); }
            100% { transform: translateY(100%); }
          }
        `}
      </style>
      <motion.div variants={containerVariants} initial="hidden" animate="visible">
        <Paper
          elevation={12}
          sx={{
            p: 4,
            maxWidth: 420,
            width: '100%',
            borderRadius: 4,
            bgcolor: 'rgba(15, 23, 42, 0.95)',
            border: '1px solid rgba(59, 130, 246, 0.3)',
            boxShadow: '0 0 40px rgba(59, 130, 246, 0.2)',
            position: 'relative',
            overflow: 'hidden',
            '&:after': {
              content: '""',
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              height: '2px',
              background: 'linear-gradient(90deg, transparent, #3b82f6, transparent)',
              animation: 'scan 3s infinite'
            }
          }}
        >
          <motion.div variants={childVariants}>
            <Typography
              variant="h4"
              align="center"
              sx={{
                fontWeight: 'bold',
                mb: 2,
                color: '#3b82f6',
                background: 'linear-gradient(45deg, #3b82f6, #9333ea)',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
                letterSpacing: '0.05em'
              }}
            >
              HUNTER AI
            </Typography>
            <Typography
              variant="body1"
              color="#94a3b8"
              align="center"
              sx={{ mb: 4, fontStyle: 'italic' }}
            >
              Your AI Interview Companion
            </Typography>
          </motion.div>

          {error && (
            <motion.div variants={childVariants}>
              <Alert 
                severity="error" 
                sx={{ 
                  mb: 3, 
                  bgcolor: 'rgba(239, 68, 68, 0.1)',
                  color: '#ef4444',
                  border: '1px solid rgba(239, 68, 68, 0.3)'
                }}
              >
                {error}
              </Alert>
            </motion.div>
          )}

          <form onSubmit={handleSubmit}>
            <motion.div variants={childVariants}>
              <TextField
                fullWidth
                label="Email Address"
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <EnvelopeIcon className="h-5 w-5 text-blue-400" />
                    </InputAdornment>
                  ),
                }}
                sx={{
                  mb: 3,
                  '& .MuiOutlinedInput-root': {
                    borderRadius: 2,
                    background: 'rgba(30, 41, 59, 0.5)',
                    color: '#e2e8f0',
                    '& fieldset': {
                      borderColor: 'rgba(59, 130, 246, 0.3)'
                    },
                    '&:hover fieldset': { 
                      borderColor: '#3b82f6' 
                    },
                    '&.Mui-focused fieldset': { 
                      borderColor: '#3b82f6',
                      boxShadow: '0 0 10px rgba(59, 130, 246, 0.3)'
                    },
                  },
                  '& .MuiInputLabel-root': {
                    color: '#94a3b8'
                  },
                  '& .MuiInputLabel-root.Mui-focused': {
                    color: '#3b82f6'
                  }
                }}
              />
            </motion.div>
            <motion.div variants={childVariants}>
              <TextField
                fullWidth
                label="Password"
                type={showPassword ? 'text' : 'password'}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <LockClosedIcon className="h-5 w-5 text-blue-400" />
                    </InputAdornment>
                  ),
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={() => setShowPassword(!showPassword)}
                        edge="end"
                      >
                        {showPassword ? (
                          <EyeSlashIcon className="h-5 w-5 text-blue-400" />
                        ) : (
                          <EyeIcon className="h-5 w-5 text-blue-400" />
                        )}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
                sx={{
                  mb: 3,
                  '& .MuiOutlinedInput-root': {
                    borderRadius: 2,
                    background: 'rgba(30, 41, 59, 0.5)',
                    color: '#e2e8f0',
                    '& fieldset': {
                      borderColor: 'rgba(59, 130, 246, 0.3)'
                    },
                    '&:hover fieldset': { 
                      borderColor: '#3b82f6' 
                    },
                    '&.Mui-focused fieldset': { 
                      borderColor: '#3b82f6',
                      boxShadow: '0 0  있고, 10px rgba(59, 130, 246, 0.3)'
                    },
                  },
                  '& .MuiInputLabel-root': {
                    color: '#94a3b8'
                  },
                  '& .MuiInputLabel-root.Mui-focused': {
                    color: '#3b82f6'
                  }
                }}
              />
            </motion.div>
            <motion.div variants={childVariants}>
              <Button
                component={motion.button}
                variants={buttonVariants}
                whileHover="hover"
                whileTap="tap"
                type="submit"
                fullWidth
                variant="contained"
                disabled={loading}
                sx={{
                  borderRadius: 2,
                  py: 1.5,
                  background: 'linear-gradient(45deg, #3b82f6, #9333ea)',
                  '&:hover': { 
                    background: 'linear-gradient(45deg, #2563eb, #7e22ce)',
                    boxShadow: '0 0 20px rgba(59, 130, 246, 0.5)'
                  },
                  textTransform: 'none',
                  fontWeight: 'bold',
                  letterSpacing: '0.05em'
                }}
              >
                {loading ? 'Initializing...' : 'Access HUNTER AI'}
              </Button>
            </motion.div>
            <motion.div variants={childVariants}>
              <Button
                fullWidth
                variant="text"
                onClick={() => navigate('/forgot-password')}
                sx={{ 
                  mt: 2, 
                  textTransform: 'none', 
                  color: '#3b82f6',
                  '&:hover': {
                    color: '#60a5fa',
                    background: 'rgba(59, 130, 246, 0.1)'
                  }
                }}
              >
                Forgot Password?
              </Button>
            </motion.div>
          </form>
        </Paper>
      </motion.div>
    </Box>
  );
};

export default Login;
